import { Component } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { InquireService } from "src/app/core/services/files/inquire/inquire.service";

@Component({
  selector: "app-inquire",
  templateUrl: "./inquire.page.html",
  styleUrls: ["./inquire.page.scss"],
})
export class InquireComponent {
  inquiryForm: FormGroup = this.formBuilder.group({
    clientName: [null, [Validators.required]],
    lastDigits: [null],
  });

  constructor(
    private formBuilder: FormBuilder,
    private inquire: InquireService
  ) {}

  inquireAboutClient() {
    if (this.inquiryForm.valid) {
      this.inquire.inquireAboutClientWithNameAndLastDigits(
        this.inquiryForm.controls["clientName"].value,
        this.inquiryForm.controls["lastDigits"].value
      );
    }
  }
}
