import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import { EnvService } from "../../env.service";
import { AlertService } from "../../alert.service";

@Injectable({
  providedIn: "root",
})
export class InquireService {
  constructor(
    private http: HttpClient,
    private env: EnvService,
    private alert: AlertService
  ) {}

  async inquireAboutClientWithNameAndLastDigits(
    clientName: string,
    lastDigits: string
  ) {
    let response = await this.http
      .get<any>(
        `${this.env.API_URL}api/Terrorism/InquireUsingNameAndLastDigits?name=${clientName}&lastDigits=${lastDigits}`
      )
      .toPromise()
      .catch((err) => {
        this.alert.showAlertError(err.error, false);
      });
    return !response["result"]
      ? this.alert.showAlertConfirm(
          "لم يتم العثور على العميل في ملف الإرهابيين",
          false
        )
      : this.alert.showAlertError(
          "تم العثور على العميل في ملف الإرهابيين",
          false
        );
  }
}
